import React from 'react';
import Home from '../../Pages/Home';
import Contact from "../../Pages/Contact";
import Gallery from "../../Pages/Gallery";
import Portfolio from "../../Pages/Portfolio";
import Error from "../../Pages/Error";

export interface Page {
    name: string
    element: React.ReactNode;
}

const Pages: Page[] = [
    {
        name: 'Contact',
        element: <Contact/>
    },
    {
        name: 'Gallery',
        element: <Gallery/>
    },
    {
        name: 'Portfolio',
        element: <Portfolio/>
    },
    {
        name: 'Home',
        element: <Home/>
    },
    {
        name: '*',
        element: <Error/>
    },
]

interface Route   {
    path: string,
    element: React.ReactNode,
  }

interface RouteMapper {
  getRoutes: (array: Page[]) => Route[],
}

const routeMapper: RouteMapper = {
    getRoutes: (array) => {
        const paths: Route[] = array.map((e) => ({ path: e.name.toLowerCase(), element: e.element }))
        paths.push({path: '/', element: <Home/> })
        return paths;
    }
}

export default routeMapper;
